/**
 * Calculates a match score between a student profile and a topic
 * Returns a score between 0-100 (0 = no match, 100 = perfect match)
 */
function calculateMatchScore(studentProfile, topic) {
  let score = 0;
  
  // 1. Specialization match (30 points max)
  if (topic.specializari.includes(studentProfile.specialization) || 
      topic.specializari.includes("Toate programele")) {
    score += 30;
  }
  
  // 2. Extract keywords from student profile
  const studentKeywords = new Set();
  
  if (studentProfile.skills) {
    studentProfile.skills
      .toLowerCase()
      .split(/[,;]/)
      .forEach(skill => studentKeywords.add(skill.trim()));
  }
  
  if (studentProfile.interests) {
    studentProfile.interests
      .toLowerCase()
      .split(/[,;]/)
      .forEach(interest => studentKeywords.add(interest.trim()));
  }
  
  if (studentProfile.careerGoals) {
    studentProfile.careerGoals
      .toLowerCase()
      .split(/[,;]/)
      .forEach(goal => studentKeywords.add(goal.trim()));
  }
  
  // 3. Match keywords against topic title (70 points max)
  const topicTitle = topic.titlu_tema.toLowerCase();
  const profesorName = topic.profesor.toLowerCase();
  
  let keywordMatches = 0;
  studentKeywords.forEach(keyword => {
    if (keyword.length > 2) { // Only consider keywords longer than 2 chars
      if (topicTitle.includes(keyword) || profesorName.includes(keyword)) {
        keywordMatches++;
      }
    }
  });
  
  // Award points based on keyword matches (up to 70 points)
  if (keywordMatches > 0) {
    score += Math.min(70, keywordMatches * 15);
  }
  
  return Math.min(100, score);
}

/**
 * Get recommended topics for a student based on their profile
 * Returns an array of topics sorted by match score (highest first)
 */
export function getRecommendedTopics(studentProfile) {
  // Map study level from form ('bachelor', 'master') to database format ('Licență', 'Masterat')
  const studyLevelMap = {
    'bachelor': 'Licență',
    'master': 'Masterat',
    'conversion': 'Conversie profesională'
  };
  
  const targetStudyLevel = studyLevelMap[studentProfile.studyLevel] || studentProfile.studyLevel;
  
  // Filter and score all topics
  const scoredTopics = fiescTopics
    .filter(topic => topic.nivel_studii === targetStudyLevel)
    .map(topic => ({
      ...topic,
      title: topic.titlu_tema,
      description: topic.titlu_tema,
      keywords: [],
      level: [topic.nivel_studii],
      professor: topic.profesor,
      matchScore: calculateMatchScore(studentProfile, topic)
    }))
    .filter(topic => topic.matchScore > 0) // Only return topics with at least some match
    .sort((a, b) => b.matchScore - a.matchScore); // Sort by match score descending
  
  // Return top 5 recommendations
  return scoredTopics.slice(0, 5);
}